var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"클리포트 게임에서 모습을 드러낸 최고 관리자. 그는 누구인가?","JPN":"クリフォトゲームで姿を現した最高管理者。彼は誰なのか？","ENG":"The Supreme Administrator reveals himself in the Qliphoth Game. Who is he?","TWN":"在逆卡巴拉遊戲中現身的最高管理者。他是誰？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"전대미문의 사건. 클리포트 게임에서 소문만 무성했던 최고 관리자가 모습을 드러냈다.","JPN":"前代未聞の事件。クリフォトゲームで噂の最高管理者が姿を現した。","ENG":"In an unprecedented case, the rumored Supreme Administrator finally appears in the Qliphoth Game.","TWN":"前所未聞的事件。在逆卡巴拉遊戲中只聞其名的最高管理者現身。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"최고 관리자……?","JPN":"最高管理者……？","ENG":"Supreme Administrator...?","TWN":"最高管理者……？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아는 사람이…… 아니었나요?","JPN":"知り合いじゃ……なかったんですか？","ENG":"Is he... someone you know?","TWN":"你不認識他嗎……？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"대부분의 전대원들은 최고 관리자가 아닌 테라브레인의 선별로 차출된다.","JPN":"ほとんどの戦隊員は最高管理者ではなく、テラブレインの選別によって呼び出される。","ENG":"Most division members are selected by Terrabrain and not the Supreme Administrator.","TWN":"大部分隊員都是由特拉大腦篩選出來的，而不是最高管理者。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"최고 관리자가 있다는 소문 정도나 들었지. 그 실체를 확인한 건 이번이 처음이야.","JPN":"最高管理者がいるという噂なら聞いている。だが、その実体を確認したのは今回が初めてだ。","ENG":"I've heard rumors that there was a Supreme Administrator, but it's my first time confirming that he really exists.","TWN":"我只是聽說過有最高管理者的傳聞，這次是第一次發現他是真實存在的。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"코핀 컴퍼니라…… 여전히 의지를 이어가겠다는 건가.","JPN":"コフィンカンパニーか……今の時代でも、その意志を繋いでいくということか。","ENG":"Coffin Company...? So he still remains committed to carrying out the will, I see.","TWN":"科芬公司……所以他也在繼續前進嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"정말 많은 것이 변했어요. 클리포트 게임에서 승리할 줄은…….","JPN":"本当に多くのものが変わりましたね。クリフォトゲームで勝利するとは……","ENG":"A lot has changed indeed. Who knew we'd win the Qliphoth Game...","TWN":"變化很大呢，沒想到會在逆卡巴拉遊戲中獲勝……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"하지만 어째서 세상은 평화로워지지 않은 걸까요?","JPN":"ですが、どうして世界は平和になっていないのでしょうか。","ENG":"But then, why hasn't the world found peace yet?","TWN":"但為什麼這個世界還是無法獲得和平呢？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"게임에서 이긴다고 다가 아니라는 거겠지.","JPN":"ゲームで勝つことがすべてではないということだろう。","ENG":"Because winning the game is not everything.","TWN":"那是因為獲勝並不是全部。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래도 이제껏 해내지 못한 일을 해냈다는 것이 중요하다.","JPN":"だが、今までできなかったことを成し遂げたということが重要だ。","ENG":"Still, what's important is that we have accomplished something that has never been done before.","TWN":"不過，重要的是我們已經完成至今未能完成的事。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"동결되어 있던 사이에…… 정말 세상이 뒤집힌 셈이 됐군.","JPN":"凍結されていた間に……本当に世の中がひっくり返ったようだ。","ENG":"While I was frozen... the world really did turn upside down.","TWN":"在我被冰封的這段時間……世界真是有翻天覆地的改變。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"적어도 지금 당장 싸우러 나가진 않아도 되겠네요.","JPN":"少なくとも、今すぐ戦いに行かなくてもよさそうですね。","ENG":"I assume that I won't have to go out to fight immediately, at least.","TWN":"至少我們現在不需要立刻出去作戰。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"지금은 정보와 지식을 습득해야 할 때다.","JPN":"今は情報と知識を習得する時だ。","ENG":"Right now, our priority lies in acquiring information and knowledge.","TWN":"現在，我們的任務是獲取資訊和更多知識。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"여러 곳의 정보도 얻을 겸…… 그래. 가이드나 해보는 건 어떤가?","JPN":"いろんな場所の情報も入手するついでに……そうだ。ガイドでもやってみるのはどうだ？","ENG":"And to obtain information from various places... Yes. How about we become guides?","TWN":"說到這個……這樣吧？試試看當導遊怎麼樣？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"가, 가이드요? 가이드는 역사나 지리에 해박해야 해요. 두 분은 좀 힘들지 않을까요?","JPN":"が、ガイドですか？　ガイドは歴史や地理に詳しくないとダメですよ。二人にはちょっと無理じゃないでしょうか？","ENG":"G-guides? But guides have to be extremely knowledgeable on history and geography. Won't it be too difficult for you two?","TWN":"導，導遊嗎？導遊需要對歷史和地理非常了解。你們兩個可能有點困難吧？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무, 물론 요즘은 카운터 가이드들이 더 선호되는 트렌드이긴 하지만…….","JPN":"も、もちろん最近はカウンターガイドがもっと好まれてはいるんですけど……","ENG":"I-I mean, there is a trend going on with Counter guides being more preferred, but...","TWN":"雖然最近制裁者導遊更受歡迎……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"시, 싫다는 건 아니에요! 저, 저는 오히려 하고 싶다고 할까…….","JPN":"い、嫌ってわけじゃないんですよ！　わ、私はむしろやりたいっていうか……","ENG":"I-I'm not saying I don't like the idea! I-I would actually love to do it...","TWN":"不，不是說不想要！相反我很喜歡……"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"카운터 가이드가 선호된다는 걸로 충분하다. 나머지는 몸으로 배우면 돼.","JPN":"カウンターガイドが好まれているということで十分だ。後は体で覚えればいい。","ENG":"If Counter guides are preferred, that's enough for me. The rest, we'll learn as we go.","TWN":"那就夠了，其他的我們走一步算一步吧。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아샤, 라비와 어렸을 적부터 여행을 자주 다녔다고 하지 않았나?","JPN":"アーシャ、ラビと幼い頃からよく旅をしていたと言ってなかったか？","ENG":"Asha, didn't you say you frequently traveled with Ravi when you were young?","TWN":"阿莎，你不是從小就經常和拉維一起旅行嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"네가 이 일에 적격이라고 생각했는데.","JPN":"君にうってつけの仕事だと思ったのだか。","ENG":"I think you're a perfect fit for this job.","TWN":"我認為你會很適合這份工作。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"저, 적격이요? 그럼요! 뭐부터 알려드릴까요?","JPN":"そ、そうですか？　もちろんです！　何から始めましょうか？","ENG":"P-perfect fit? Of course! What should I teach you first?","TWN":"我……很合適嗎？那好！需要我告訴你什麼？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"침식체와 최초 조우? 대정화 전쟁? 대균열 관측? 브리트라 요격전?","JPN":"侵食体との初遭遇？　大浄化戦争？　大亀裂の観測？　ブリトラ迎撃戦？","ENG":"The first encounter with C.O.s? The Grand Purification War? The observation of Grand Dimension Crevice? The Britra Interception?","TWN":"與侵蝕體的首次遭遇？大淨化作戰？對大峽谷的觀測結果？還是佈雷特攔截戰？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"……아니, 나한테 그걸 알려줄 필요는 없다. 따로 찾아보도록 하지.","JPN":"……いや、私にそんなことを教える必要はない。各々で調べてみるとしよう。","ENG":"...No. There's no need for you to tell me about them. I'll research them myself.","TWN":"……不，不需要告訴我那些。我會自己去查的。"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"우선, 네 명의로 사무소를 차릴 계획인데, 괜찮나?","JPN":"まず、君の名義で事務所を開業するつもりだが、大丈夫か？","ENG":"First, I'd like to open an office under your name. Would that be all right?","TWN":"首先，我計畫以你的名義開一家公司，可以嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"사무소요?","JPN":"事務所ですか？","ENG":"An office?","TWN":"公司嗎？"},"stage":{"bg":"COUNTRYROAD_02","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};